INSERT INTO `movies` (`id`, `tmdb_id`, `title`, `description`, `poster_path`, `release_date`, `price`, `created_at`, `updated_at`, `category`) VALUES
(2464, 1359227, 'LEGO Marvel Avengers: Mission Demolition', 'A young, aspiring hero and superhero fan inadvertently unleashes a powerful new villain looking to rid the world of the Avengers.', 'https://image.tmdb.org/t/p/w500/4KfgyzCgJeG0XJDbqNztdP730Pv.jpg', '2024-10-17', 7.26, '2025-04-15 10:12:40', '2025-04-15 17:08:44', 'Animation'),
(2465, 9320, 'The Avengers', 'British Ministry agent John Steed, under direction from \"Mother\", investigates a diabolical plot by arch-villain Sir August de Wynter to rule the world with his weather control machine. Steed investigates the beautiful Doctor Mrs. Emma Peel, the only suspect, but simultaneously falls for her and joins forces with her to combat Sir August.', 'https://image.tmdb.org/t/p/w500/1p5thyQ4pCy876HpdvFARqJ62N9.jpg', '1998-08-13', 12.02, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2466, 40081, 'Crippled Avengers', 'A group of martial artists seek revenge after being crippled by Tu Tin-To, a martial arts master, and his son.', 'https://image.tmdb.org/t/p/w500/eKdvNCKtiuUFvwCXtpwISw8jqZ5.jpg', '1978-12-21', 19.32, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2467, 257346, 'Avengers Confidential: Black Widow & Punisher', 'When the Punisher takes out a black-market weapons dealer, he stumbles upon a far-reaching terrorist plot devised by a group known as Leviathan.', 'https://image.tmdb.org/t/p/w500/wJcyYVRPZDOZOD2w0r2R6wuZqqN.jpg', '2014-04-19', 10.61, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Animation'),
(2468, 1154598, 'LEGO Marvel Avengers: Code Red', 'The Avengers gather to celebrate their latest victory, but their celebration is quickly interrupted by the mysterious disappearance of Black Widow\'s father, Red Guardian. As the Avengers investigate, they discover that Red Guardian isn\'t the only one missing when they meet a dangerous new foe quite unlike anything they\'ve ever encountered before.', 'https://image.tmdb.org/t/p/w500/rDzig50dj7VpLwJ7SThbamETK1G.jpg', '2023-10-26', 8.08, '2025-04-15 10:12:40', '2025-04-15 17:08:44', 'Animation'),
(2469, 299534, 'Avengers: Endgame', 'After the devastating events of Avengers: Infinity War, the universe is in ruins due to the efforts of the Mad Titan, Thanos. With the help of remaining allies, the Avengers must assemble once more in order to undo Thanos\' actions and restore order to the universe once and for all, no matter what consequences may be in store.', 'https://image.tmdb.org/t/p/w500/ulzhLuWrPK07P1YkdWQLZnQh1JL.jpg', '2019-04-24', 15.55, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Adventure'),
(2470, 99861, 'Avengers: Age of Ultron', 'When Tony Stark tries to jumpstart a dormant peacekeeping program, things go awry and EarthÃ¢â¬â¢s Mightiest Heroes are put to the ultimate test as the fate of the planet hangs in the balance. As the villainous Ultron emerges, it is up to The Avengers to stop him from enacting his terrible plans, and soon uneasy alliances and unexpected action pave the way for an epic and unique global adventure.', 'https://image.tmdb.org/t/p/w500/4ssDuvEDkSArWEdyBl2X5EHvYKU.jpg', '2015-04-22', 14.95, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2472, 63441, 'Masked Avengers', 'Philip Kwok plays a repentant killer who vows to destroy the masked gang of which he was a member. A young fighter and his martial arts brothers come to the town to catch the killers, but one of them is not to be trusted!', 'https://image.tmdb.org/t/p/w500/vr54E7RjvMLE4rFgb1NPgZdnpj6.jpg', '1981-05-15', 12.68, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2473, 14611, 'Ultimate Avengers 2', 'Mysterious Wakanda lies in the darkest heart of Africa, unknown to most of the world. An isolated land hidden behind closed borders, fiercely protected by its young king: Black Panther. But when brutal alien invaders attack, the threat leaves Black Panther with no option but to go against the sacred decrees of his people and ask for help from outsiders.', 'https://image.tmdb.org/t/p/w500/2bfVNvLKWaxFh1LiOKlvxgiHOXn.jpg', '2006-08-08', 16.56, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Adventure'),
(2474, 347158, 'Bikini Avengers', 'When the Jade Empress steals the world\'s largest diamonds, super heroes Bikini Avenger and Thong Girl must stop her before she uses the gems to build a dangerous sci-fi weapon.', 'https://image.tmdb.org/t/p/w500/ehTYWuPKwl8sXPX0I6LnvJUDaVl.jpg', '2015-02-24', 9.66, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Comedy'),
(2475, 1003596, 'Avengers: Doomsday', 'The Avengers, Wakandans, Fantastic Four, Thunderbolts, and X-Men all fight against Doctor Doom. Plot TBA.', 'https://image.tmdb.org/t/p/w500/6eB2oh1SplddsZYCdayrIdrIGLd.jpg', '2026-04-29', 16.26, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Science Fiction'),
(2476, 14613, 'Next Avengers: Heroes of Tomorrow', 'The children of the Avengers hone their powers and go head to head with the very enemy responsible for their parents\' demise.', 'https://image.tmdb.org/t/p/w500/1y4J9HZJoTIMdt77wCq80uXaQJ.jpg', '2008-09-02', 10.08, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Animation'),
(2477, 296491, '3 Avengers', 'Ursus and his sword-wielding companions run head-on against a usurper of a throne.', 'https://image.tmdb.org/t/p/w500/skGMVZ41KWezqKa29g8bqpXfLlV.jpg', '1964-11-26', 8.06, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2478, 1003598, 'Avengers: Secret Wars', 'An upcoming film in Phase 6 of the Marvel Cinematic Universe (MCU) and the finale of The Multiverse Saga. Plot TBA.', 'https://image.tmdb.org/t/p/w500/f0YBuh4hyiAheXhh4JnJWoKi9g5.jpg', '2027-05-05', 11.28, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Science Fiction'),
(2479, 157421, 'Avengers from Hell', 'Three macabre short stories about gambling, vengeance and homicide.', 'https://image.tmdb.org/t/p/w500/AuhPoFUKgYBRNDYjsTOPHE56Nzz.jpg', '1981-04-02', 14.49, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Fantasy'),
(2480, 323660, 'Avengers Grimm', 'When Rumpelstiltskin destroys the Magic Mirror and escapes to the modern world, the four princesses of \"Once Upon a Time\"-Cinderella, Sleeping Beauty, Snow White, and Rapunzel-are sucked through the portal too. Well-trained and endowed with magical powers, the four women must fight Rumpelstiltskin and his army of thralls before he enslaves everyone on Earth.', 'https://image.tmdb.org/t/p/w500/9sdAHQxt53W8gZKivX0Pdk4DuXA.jpg', '2015-03-17', 18.48, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2481, 1168015, 'People\'s Avengers', 'About the partisan movement during the Great Patriotic War.', 'https://image.tmdb.org/t/p/w500/D1QpslQSEZ9iCiBr6B5oZsIhOR.jpg', '1943-11-14', 13.61, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Documentary'),
(2482, 65591, 'The New Adventures of the Elusive Avengers', 'The action takes place in 1920 during the Civil War.  Crimea on the eve of complete liberation from the White Guards. Returning from patrol, the four brave Ã¢â¬ÅelusiveÃ¢â¬Â knocked down an airplane. In the field bag of the captured pilot, they find a secret report, which speaks of the existence of defensive fortifications around the coastal city, which the Reds have yet to take. Young heroes get the task to get a map of fortifications and go to the city...', 'https://image.tmdb.org/t/p/w500/pulCmFhk5GkeoV9a6nVg46lo1a3.jpg', '1968-11-04', 8.66, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2483, 83876, 'The Avenging Eagle', 'Eagle Chief Yoh Xi-hung raises orphans to be his personal killers. One such is Chik Ming-sing who now wants to put his killer life behind him. When the Eagle Clan come after him, a stranger called Cheuk comes to his assistance It turns out that Cheuk is the son of a family who were robbed and murdered by the Eagles. Now they will team up to destroy the evil clan.', 'https://image.tmdb.org/t/p/w500/tpOVfLNNmWQFNJrfrAnLmdsx8pT.jpg', '1978-09-13', 13.31, '2025-04-15 10:12:40', '2025-04-15 10:15:37', 'Action'),
(2484, 857702, 'LEGO Star Wars : Histoires terrifiantes', 'AprÃÂ¨s s\'ÃÂªtre ÃÂ©crasÃÂ©s sur la planÃÂ¨te volcanique Mustafar, Poe et BB-8 cherchent de l\'aide dans l\'ancien chÃÂ¢teau de Dark Vador. Ils y rencontrent un Hutt fourbe, un mÃÂ©canicien courageux, et l\'ancien serviteur de Dark Vador, VaneÃÂ©, qui leur raconte trois histoires terrifiantes d\'artefacts ancestraux et de mÃÂ©chants iconiques de l\'univers de Star Wars.', 'https://image.tmdb.org/t/p/w500/t5Ibjcr0LoqjXsYXOZM0SdCjTSE.jpg', '2021-10-01', 15.77, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2485, 980804, 'LEGO Star Wars : C\'est l\'ÃÂ©tÃÂ© !', 'L\'histoire a lieu aprÃÂ¨s les ÃÂ©vÃÂ©nements de Star Wars: Episode IX. On y retrouve Rose, Rey, Finn, Poe et Chewbacca qui vont s\'offrir une pause ensoleillÃÂ©e bien mÃÂ©ritÃÂ©e aprÃÂ¨s avoir vaincu Palpatine. Tout au long de ce spÃÂ©cial, ils visiteront d\'autres lieux emblÃÂ©matiques de Star Wars tout en interagissant avec divers personnages de la franchise, notamment C-3PO, Lando, Boba Fett, Obi-Wan Kenobi, Jabba le Hutt, Anakin Skywalker, Dark Vador, Kylo Ren, Finn, Han Solo, Leia et Palpatine.', 'https://image.tmdb.org/t/p/w500/uhE1v8Td7k4csrTV5Xfvvh0V6jD.jpg', '2022-08-05', 16.73, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2486, 1171423, 'LEGO Jurassic Park : La version non officielle', 'Dans le confort de son salon et aprÃÂ¨s avoir trouvÃÂ© son journal personnel, le Dr Ian Malcolm, mathÃÂ©maticien de la thÃÂ©orie du chaos, toujours aussi charmant et dÃÂ©sormais lÃÂ©gÃÂ¨rement plus ÃÂ¢gÃÂ©, raconte l\'histoire de ce qui s\'est passÃÂ© cette terrible nuit ÃÂ  Jurassic Park ! Comme lui seul peut le faire, le Dr Malcolm trouve un moyen d\'ajouter son propre humour et son propre style pour redonner vie ÃÂ  cette histoire poignante. Une destination remplie de dinosaures vivants pour le plaisir de la famille et des enfants - qu\'est-ce qui pourrait mal tourner ? Absolument tout... comme il l\'avait prÃÂ©dit !', 'https://image.tmdb.org/t/p/w500/tWcIgXKnMKDtLIVTSYHjvagmWn1.jpg', '2023-10-10', 9.37, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2487, 417047, 'Barbie et ses sÃâurs : Ãâ¬ la recherche des chiots', 'Dans cette aventure rafraichissante, Barbie et ses sÃâurs vont dÃÂ©couvrir que la vie est plus belle quand on la partage ÃÂ  plusieurs. ArrivÃÂ©es sur lÃ¢â¬â¢ÃÂ®le paradisiaque oÃÂ¹ se dÃÂ©roule la grande compÃÂ©tition de danse de Chelsea, les jeunes filles et leurs chiots dÃÂ©cident de faire un rapide dÃÂ©tour par le festival du Cheval dansant. Mais durant lÃ¢â¬â¢ÃÂ©vÃÂ©nement, leurs petits amis disparaissent. Les sÃâurs partent alors ÃÂ  leur recherche ; mais arriveront-elles ÃÂ  les retrouver ÃÂ  temps pour le spectacle de Chelsea ? Dans cette histoire pleine de joie, les filles devront recourir ÃÂ  leur imagination et joindre leurs efforts pour retrouver leurs petits chiots partis vivre leur propre aventure.', 'https://image.tmdb.org/t/p/w500/iGCleblhU2GrhekBmQLlVP49uhd.jpg', '2016-10-04', 13.12, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2488, 732670, 'LEGO Star Wars : Joyeuses fÃÂªtes', 'Rey et BB-8 se lancent dans une quÃÂªte pour acquÃÂ©rir une connaissance plus approfondie de la Force, mais leur visite dans un mystÃÂ©rieux temple Jedi les envoie ÃÂ  travers le temps et l\'espace. Rey interagit avec Luke Skywalker, Dark Vador, Obi-Wan Kenobi, Yoda et d\'autres personnages dans certains des moments les plus apprÃÂ©ciÃÂ©s de la franchise. Ils tentent de revenir ÃÂ  temps pour le festin du jour de la vie.', 'https://image.tmdb.org/t/p/w500/aibbIWRyZcr2yIXWy1TlOZ8YboY.jpg', '2020-11-17', 14.59, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2489, 622230, 'LEGO Marvel Spider-Man: Vexed by Venom', 'A cause de Green Goblin et ÃÂ  Venom, le vol technologique a atteint un niveau record : notre ami Spider-Man peut-il mettre fin ÃÂ  leur mystÃÂ©rieux stratagÃÂ¨me avant que toute la ville de New York ne soit dÃÂ©truite ?', 'https://image.tmdb.org/t/p/w500/gTo2r8nNU3ZYAS6DqdeSp1VEqkq.jpg', '2019-08-03', 14.72, '2025-04-15 10:12:44', '2025-04-15 10:12:44', 'unknown'),
(2490, 872585, 'Oppenheimer', 'The story of J. Robert Oppenheimer\'s role in the development of the atomic bomb during World War II.', 'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg', '2023-07-19', 7.87, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
(2491, 384470, 'The Ballad of Oppenheimer Park', 'The Ballad of Oppenheimer Park is a film that celebrates the everyday life of a group of Indigenous people, exiles from Canadian reserves, who, over a fleeting summer, hang out in a contested park in Vancouver. Through direct participation in the filmmaking process, the day to day becomes a ceremonial space in the ongoing confrontation against law and order.', 'https://image.tmdb.org/t/p/w500/x2I6MgQOpOvtWGzZZ2LktFlF5MQ.jpg', '2016-03-09', 14.73, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2492, 1149947, 'To End All War: Oppenheimer & the Atomic Bomb', 'Explore how one man\'s relentless drive and invention of the atomic bomb changed the nature of war forever, led to the deaths of hundreds of thousands of people and unleashed mass hysteria.', 'https://image.tmdb.org/t/p/w500/xwkYWcs8aypUtk3xDRUh0ndo4GA.jpg', '2023-07-09', 16.83, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2493, 1156529, 'The Oppenheimer Case', 'During World War II, the American physicist Robert Oppenheimer was at the head of the research work for the production of the atomic bomb. He was removed from that position in 1953 due to disagreements with the US Atomic Commission regarding the development of the hydrogen bomb. The investigation that was conducted against him during the infamous time of anti-communist hysteria and the \"witch hunt\" during the time of Senator McCarthy is testimony to the great moral and psychological dilemma in which the scientists of that era found themselves.', 'https://image.tmdb.org/t/p/w500/1ufp5zjkkjXoSHLN7milIPNOZtS.jpg', '1970-02-02', 16.73, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
(2494, 401783, 'The Trials of J. Robert Oppenheimer', 'J. Robert Oppenheimer was a national hero, the brilliant scientist who during WWII led the scientific team that created the atomic bomb. But after the bomb brought the war to an end, in spite of his renown and his enormous achievement, America turned on him - humiliated and cast him aside. The question the film asks is, \"Why?\"', 'https://image.tmdb.org/t/p/w500/nw2snwOxddwZRhDL1cW9q3Lr9Gt.jpg', '2008-03-24', 11.31, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2495, 1329275, 'Oppenheimer and The Manhattan Project', 'Delves deep into the life and complex legacy of J. Robert Oppenheimer, one of the most enigmatic and influential figures of the 20th century.', 'https://image.tmdb.org/t/p/w500/xAHfLoQgTOuzABAXqlhQtdrujB2.jpg', '2024-10-01', 9.62, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2496, 1152711, 'Inside Christopher Nolan\'s Oppenheimer', 'A look behind the scenes of Christopher Nolan\'s film \"Oppenheimer\" about an American scientist and his role in the development of the atomic bomb.', 'https://image.tmdb.org/t/p/w500/p3mB2IFZAhFlBPwlNbv2ouzwxx0.jpg', '2023-07-15', 16.82, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2497, 1142906, 'Oppenheimer: The Real Story', 'J. Robert Oppenheimer, a physics professor known for creating the atomic bomb during WWII. He witnessed the first atomic bomb detonation in New Mexico in 1945. This film examines Oppenheimer\'s life, from his early years to his involvement with nuclear physics and his later advocacy for nuclear weapons controls, with interviews and insights from those who knew him and impacted by his legacy.', 'https://image.tmdb.org/t/p/w500/ecYTEmn3JBZyWbqwzjmBFfGvi3U.jpg', '2023-07-17', 11.28, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2498, 1143770, 'Oppenheimer After Trinity', 'This captivating documentary on J. Robert Oppenheimer, the architect of the atomic bomb, explores his journey before the historic test and reveals the burden he carried after. De-classified documents, rare film footage and exclusive interviews, including Oppenheimer\'s grandson, show an intimate exploration of the burden Oppenheimer carried and the profound global impact still being debated today.', 'https://image.tmdb.org/t/p/w500/6Mq4O6RyKXWnXOhor71qzV92n7n.jpg', '2023-04-22', 8.70, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2499, 1230570, 'The Real Oppenheimer', '', 'https://image.tmdb.org/t/p/w500/jUqSMGViJoorV8bnZpgp6HXpG42.jpg', '2023-08-01', 8.35, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2500, 1189676, 'Oppenheimer: Genius or Madman?', 'This documentary explores famous figure J. Robert Oppenheimer, an American theoretical physicist who was called, \"father of the atomic bomb\" for his role in the Manhattan Project.', 'https://image.tmdb.org/t/p/w500/86smfQwQPC81j02ELmalmQZu2OL.jpg', '2023-07-25', 19.00, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2501, 604445, 'In der Sache I. Robert Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1964-01-23', 11.54, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'TV Movie'),
(2502, 1243157, 'Innovations in Film: 65mm Black and White Film in Oppenheimer', 'FotoKem gives in-depth tour of the new scientific and artistic workflows that had to be invented in order to realize Christopher Nolan\'s unique vision of using both color and black & white 65mm film in the same motion picture', 'https://image.tmdb.org/t/p/w500/iClm6meiTIDJEYrl2zrwnxiwU4X.jpg', '2023-11-22', 14.05, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2503, 288378, 'The Oppenheim Family', 'Directed by Grigori Roshal.', 'https://image.tmdb.org/t/p/w500/kuOAkBeSnohQq9SGlpZaEER4jkt.jpg', '1939-01-02', 13.62, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'unknown'),
(2504, 1156443, 'Oppenheimer: O GÃÂªnio Arrependido', '', 'https://image.tmdb.org/t/p/w500/znL8ZS2cZrv3mnfd0cBor6GSvB2.jpg', '2023-06-19', 19.80, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
(2505, 356886, 'In der Sache J. Robert Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1981-11-01', 19.52, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
(2506, 517887, 'Josef SÃÂ¼ÃÅ¸ Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1984-01-24', 13.84, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
(2507, 824266, 'Joshua Oppenheimer on Night and Fog', 'The Academy Award-winning director of the heavy documentary \'The Act of Killing\' discusses his philosophies in documentary filmmaking, the horrors of \'Night and Fog,\' and what makes it the impactful film that it is.', 'https://image.tmdb.org/t/p/w500/r2g5F3W6aAVwKrOzdOwXcMcP1Fu.jpg', '2016-07-19', 10.95, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Documentary'),
(2508, 608769, 'Schaffende HÃÂ¤nde: Max Oppenheimer', 'In the best films of Hans CÃÂ¼rlis the acts of filming and painting coincide. The portrait of a portraitist. Max Oppenheimer (Mopp; 1885-1954) was a well-known portraitist and painter of musicians and orchestras. In this case he paints the portrait of Heinrich Mann, while CÃÂ¼rlis portrays Heinrich Mann as he is being portrayed by Mopp and Mopp as he is portraying Heinrich Mann. Thus the \"Schaffende HÃÂ¤nde\" Ã¢â¬â Creative Hands Ã¢â¬â are both those of the painter and those of the film director CÃÂ¼rlis: these are hand-made films.', 'https://via.placeholder.com/500x750?text=No+Image', '1924-01-01', 10.95, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'unknown'),
(2509, 1187380, 'Oppenheimerin tapaus', 'A television play adaptation of the trial against Robert Oppenheimer.', 'https://image.tmdb.org/t/p/w500/50Rov4ZLE88brOkKFt9GdkxDXYT.jpg', '1967-10-11', 11.18, '2025-04-15 10:13:13', '2025-04-15 10:13:13', 'Drama'),
